begin;
create table public.rate_limit_buckets(key_hash text primary key,window_started_at timestamptz not null,count integer not null check(count>0),updated_at timestamptz not null default now());
alter table public.rate_limit_buckets enable row level security;
revoke all on public.rate_limit_buckets from anon,authenticated;
create or replace function public.consume_rate_limit(p_key_hash text,p_limit integer,p_window_seconds integer) returns boolean language plpgsql security definer set search_path=public as $$declare allowed boolean;begin if p_limit<1 or p_window_seconds<1 then raise exception 'invalid_rate_limit';end if;insert into rate_limit_buckets(key_hash,window_started_at,count) values(p_key_hash,now(),1) on conflict(key_hash) do update set window_started_at=case when rate_limit_buckets.window_started_at<=now()-make_interval(secs=>p_window_seconds) then now() else rate_limit_buckets.window_started_at end,count=case when rate_limit_buckets.window_started_at<=now()-make_interval(secs=>p_window_seconds) then 1 else rate_limit_buckets.count+1 end,updated_at=now() returning count<=p_limit into allowed;return allowed;end$$;
revoke all on function public.consume_rate_limit(text,integer,integer) from public,anon,authenticated;
create policy business_owner_insert on public.seller_businesses for insert to authenticated with check(owner_profile_id=auth.uid());
create or replace function public.create_campaign_atomic(p_product jsonb,p_campaign jsonb,p_variants jsonb) returns uuid language plpgsql security invoker set search_path=public as $$declare s uuid;p uuid;c uuid;v jsonb;begin select public.current_seller_id() into s;if s is null then raise exception 'seller_business_required';end if;insert into products(seller_id,name,description,category,status) values(s,p_product->>'name',coalesce(p_product->>'description',''),p_product->>'category','active') returning id into p;insert into campaigns(seller_id,product_id,short_code,status,stock_mode,payment_mode,deposit_value,seller_minimum_take_home_kobo,seller_purchase_cost_kobo,referral_reward_kobo,public_price_kobo,reservation_minutes,ends_at,expected_fulfilment_at,allow_restock_interest,allow_substitution,chat_fallback_enabled,pricing_snapshot) values(s,p,p_campaign->>'shortCode','active',(p_campaign->>'stockMode')::stock_mode,(p_campaign->>'paymentMode')::payment_mode,(p_campaign->>'depositValue')::integer,(p_campaign->>'sellerMinimumTakeHomeKobo')::bigint,nullif(p_campaign->>'sellerPurchaseCostKobo','')::bigint,(p_campaign->>'referralRewardKobo')::bigint,(p_campaign->>'publicPriceKobo')::bigint,coalesce((p_campaign->>'reservationMinutes')::integer,30),nullif(p_campaign->>'endsAt','')::timestamptz,nullif(p_campaign->>'expectedFulfilmentAt','')::timestamptz,coalesce((p_campaign->>'allowRestockInterest')::boolean,true),coalesce((p_campaign->>'allowSubstitution')::boolean,false),coalesce((p_campaign->>'chatFallbackEnabled')::boolean,true),p_campaign->'pricingSnapshot') returning id into c;for v in select * from jsonb_array_elements(p_variants) loop insert into product_variants(product_id,sku,option_1_name,option_1_value,option_2_name,option_2_value,available_quantity,is_active) values(p,v->>'sku',nullif(v->>'option1Name',''),nullif(v->>'option1Value',''),nullif(v->>'option2Name',''),nullif(v->>'option2Value',''),nullif(v->>'availableQuantity','')::integer,true);end loop;return c;end$$;
grant execute on function public.create_campaign_atomic(jsonb,jsonb,jsonb) to authenticated;
commit;
